const ChatInterface = () => {
  const { user, activeSession, createChatSession, sendMessage } = useUser();
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleNewChat = async () => {
    try {
      const sessionName = `对话 ${new Date().toLocaleString()}`;
      await createChatSession(sessionName);
      setMessages([]);
      toast.success('新对话已创建');
    } catch (error) {
      console.error('创建新对话失败:', error);
    }
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();

    if (!inputValue.trim() || isLoading) return;

    if (!activeSession) {
      await handleNewChat();
      return;
    }

    const userMessage = inputValue.trim();
    setInputValue('');
    setIsLoading(true);
    setIsTyping(true);

    // 添加用户消息到界面
    const newUserMessage = {
      id: Date.now(),
      content: userMessage,
      type: 'user',
      timestamp: new Date()
    };
    setMessages(prev => [...prev, newUserMessage]);

    try {
      // 发送消息到后端
      await sendMessage(activeSession.id, userMessage, 'user');

      // 调用AI聊天接口
      const aiResponse = await apiService.chatWithAI(user.id, userMessage);

      // 添加AI响应到界面
      const aiMessage = {
        id: Date.now() + 1,
        content: aiResponse.ai_response,
        type: 'assistant',
        timestamp: new Date(),
        extracted_elements: aiResponse.extracted_elements,
        recommendation_triggered: aiResponse.recommendation_triggered
      };

      setMessages(prev => [...prev, aiMessage]);

      // 如果触发了推荐，获取艺术品推荐
      if (aiResponse.recommendation_triggered) {
        try {
          const recommendations = await apiService.getArtworkRecommendations({
            user_id: user.id,
            extracted_elements: aiResponse.extracted_elements,
            user_profile: aiResponse.user_profile
          });

          // 添加推荐消息
          const recommendationMessage = {
            id: Date.now() + 2,
            content: '为您推荐以下艺术作品:',
            type: 'recommendation',
            timestamp: new Date(),
            recommendations: recommendations
          };

          setMessages(prev => [...prev, recommendationMessage]);
        } catch (error) {
          console.error('获取推荐失败:', error);
        }
      }

      // 保存AI响应消息
      await sendMessage(activeSession.id, aiResponse.ai_response, 'assistant');

    } catch (error) {
      console.error('发送消息失败:', error);
      toast.error('发送消息失败，请重试');

      // 添加错误消息
      const errorMessage = {
        id: Date.now() + 1,
        content: '抱歉，我现在无法回复您的消息。请稍后再试。',
        type: 'assistant',
        timestamp: new Date(),
        isError: true
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
      setIsTyping(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage(e);
    }
  };

  const formatTime = (date) => {
    return date.toLocaleTimeString('zh-CN', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });
  };

  const renderMessage = (message) => {
    const isUser = message.type === 'user';

    return (
      <Message key={message.id} $isUser={isUser}>
        <MessageAvatar $isUser={isUser}>
          {isUser ? <User size={20} /> : <Bot size={20} />}
        </MessageAvatar>
        <div style={{ flex: 1 }}>
          <MessageBubble $isUser={isUser}>
            {message.content}

            {message.type === 'recommendation' && message.recommendations && (
              <RecommendationCard>
                <RecommendationTitle>
                  <Palette size={16} />
                  艺术品推荐
                </RecommendationTitle>
                <RecommendationText>
                  {message.recommendations.slice(0, 3).map((artwork, index) => (
                    <div key={index} style={{ marginBottom: '0.5rem' }}>
                      <strong>{artwork.title}</strong> - {artwork.artist}
                      <br />
                      <small>{artwork.description?.substring(0, 100)}...</small>
                    </div>
                  ))}
                </RecommendationText>
              </RecommendationCard>
            )}

            {message.recommendation_triggered && (
              <div style={{ 
                marginTop: '0.5rem', 
                padding: '0.5rem', 
                background: 'rgba(255,255,255,0.1)', 
                borderRadius: '8px',
                fontSize: '0.9rem'
              }}>
                <Heart size={14} style={{ marginRight: '0.3rem' }} />
                已为您触发个性化推荐
              </div>
            )}
          </MessageBubble>
          <MessageTime $isUser={isUser}>
            {formatTime(message.timestamp)}
          </MessageTime>
        </div>
      </Message>
    );
  };

  if (!user) {
    return <LoadingSpinner />;
  }

  return (
    <ChatContainer>
      <ChatHeader>
        <ChatTitle>
          <MessageCircle size={24} />
          AI 艺术助手
          {activeSession && (
            <span style={{ fontSize: '1rem', color: '#666', fontWeight: 'normal' }}>
              - {activeSession.session_name}
            </span>
          )}
        </ChatTitle>
        <NewChatButton onClick={handleNewChat}>
          <Plus size={16} />
          新对话
        </NewChatButton>
      </ChatHeader>

      <ChatBody>
        <MessagesContainer>
          {messages.length === 0 ? (
            <EmptyState>
              <EmptyStateIcon>
                <Sparkles size={40} />
              </EmptyStateIcon>
              <h3>开始您的艺术探索之旅</h3>
              <p>告诉我您的心情或艺术偏好，我将为您推荐最适合的艺术作品</p>
            </EmptyState>
          ) : (
            messages.map(renderMessage)
          )}

          {isTyping && (
            <TypingIndicator>
              <Bot size={16} />
              AI正在思考中...
            </TypingIndicator>
          )}

          <div ref={messagesEndRef} />
        </MessagesContainer>

        <InputContainer>
          <InputForm onSubmit={handleSendMessage}>
            <InputWrapper>
              <MessageInput
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={
                  activeSession 
                    ? "分享您的心情或艺术偏好..." 
                    : "开始新对话，告诉我您的心情..."
                }
                disabled={isLoading}
              />
            </InputWrapper>
            <SendButton 
              type="submit" 
              disabled={!inputValue.trim() || isLoading}
            >
              <Send size={20} />
            </SendButton>
          </InputForm>
        </InputContainer>
      </ChatBody>
    </ChatContainer>
  );
};

export default ChatInterface;
